SELECT 
FROM fees f
WHERE f.deleted_at IS NULL

    AND f.status = #{status}


    AND f.employee_id = #{employeeId}


    AND f.dormitory_id = #{dormitoryId}


    AND f.period_start >= #{periodStart}


    AND f.period_end <= #{periodEnd}

ORDER BY f.created_at DESC
LIMIT #{offset}, #{pageSize}

